import React, { useEffect, useState } from 'react';
import '../../styles/storekeeper/storekeeper-inventory.css';
import api from '../../services/api';

const StorekeeperInventory = () => {
  const [items, setItems] = useState([]);
  const [categories, setCategories] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCategory, setSelectedCategory] = useState('');
  const [selectedStatus, setSelectedStatus] = useState('');
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState(null);

  const [formData, setFormData] = useState({
    item_code: '',
    item_name: '',
    category_id: '',
    unit: '',
    unit_price: '',
    min_quantity: '',
    max_quantity: '',
    supplier: '',
    description: '',
    status: 'ACTIVE',
  });

  useEffect(() => {
    fetchItems();
    fetchCategories();
  }, []);

  const fetchItems = async () => {
    try {
      setLoading(true);
      const res = await api.get('/inventory/items');
      setItems(res.data?.data || []);
      setError(null);
    } catch (err) {
      console.error('Lỗi khi tải sản phẩm:', err);
      setError('Không thể tải danh sách sản phẩm');
    } finally {
      setLoading(false);
    }
  };

  const fetchCategories = async () => {
    try {
      const res = await api.get('/inventory/categories');
      setCategories(res.data?.data || []);
    } catch (err) {
      console.error('Lỗi khi tải danh mục:', err);
    }
  };

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({
      ...prev,
      [name]: value,
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      if (!formData.item_code || !formData.item_name || !formData.category_id || !formData.unit) {
        alert('Vui lòng nhập đầy đủ thông tin');
        return;
      }

      if (editingId) {
        await api.put(`/inventory/items/${editingId}`, formData);
        alert('Cập nhật sản phẩm thành công');
      } else {
        await api.post('/inventory/items', formData);
        alert('Tạo sản phẩm thành công');
      }

      fetchItems();
      setShowForm(false);
      setEditingId(null);
      resetForm();
      setError(null);
    } catch (err) {
      console.error('Lỗi:', err);
      setError(err.response?.data?.message || 'Không thể lưu sản phẩm');
    }
  };

  const handleEdit = (item) => {
    setFormData({
      item_code: item.item_code,
      item_name: item.item_name,
      category_id: item.category_id,
      unit: item.unit,
      unit_price: item.unit_price,
      min_quantity: item.min_quantity,
      max_quantity: item.max_quantity,
      supplier: item.supplier || '',
      description: item.description || '',
      status: item.status,
    });
    setEditingId(item.item_id);
    setShowForm(true);
  };

  const handleDelete = async (itemId) => {
    if (window.confirm('Bạn chắc chắn muốn xóa sản phẩm này?')) {
      try {
        await api.delete(`/inventory/items/${itemId}`);
        alert('Xóa sản phẩm thành công');
        fetchItems();
      } catch (err) {
        console.error('Lỗi khi xóa:', err);
        alert(err.response?.data?.message || 'Không thể xóa sản phẩm');
      }
    }
  };

  const resetForm = () => {
    setFormData({
      item_code: '',
      item_name: '',
      category_id: '',
      unit: '',
      unit_price: '',
      min_quantity: '',
      max_quantity: '',
      supplier: '',
      description: '',
      status: 'ACTIVE',
    });
  };

  const handleCloseForm = () => {
    setShowForm(false);
    setEditingId(null);
    resetForm();
  };

  const filteredItems = items.filter((item) => {
    const matchSearch =
      item.item_name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      item.item_code.toLowerCase().includes(searchTerm.toLowerCase());
    const matchCategory = !selectedCategory || item.category_id === parseInt(selectedCategory);
    const matchStatus = !selectedStatus || item.status === selectedStatus;
    return matchSearch && matchCategory && matchStatus;
  });

  return (
    <div className="storekeeper-inventory__page">
      <div className="storekeeper-inventory__header">
        <h1>Quản lý sản phẩm kho</h1>
        <p>Thêm, sửa, xóa sản phẩm trong kho</p>
      </div>

      {error && (
        <div className="storekeeper-inventory__error">
          <p>{error}</p>
        </div>
      )}

      <div className="storekeeper-inventory__filters">
        <input
          type="text"
          placeholder="🔍 Tìm kiếm mã hoặc tên sản phẩm..."
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
          className="storekeeper-inventory__search"
        />
        <select
          value={selectedCategory}
          onChange={(e) => setSelectedCategory(e.target.value)}
          className="storekeeper-inventory__filter"
        >
          <option value="">Tất cả danh mục</option>
          {categories.map((cat) => (
            <option key={cat.category_id} value={cat.category_id}>
              {cat.category_name}
            </option>
          ))}
        </select>
        <select
          value={selectedStatus}
          onChange={(e) => setSelectedStatus(e.target.value)}
          className="storekeeper-inventory__filter"
        >
          <option value="">Tất cả trạng thái</option>
          <option value="ACTIVE">Hoạt động</option>
          <option value="INACTIVE">Không hoạt động</option>
        </select>
        <button onClick={() => setShowForm(true)} className="storekeeper-inventory__button-primary">
          ➕ Thêm sản phẩm
        </button>
      </div>

      {showForm && (
        <div className="storekeeper-inventory__modal">
          <div className="storekeeper-inventory__modal-content">
            <div className="storekeeper-inventory__modal-header">
              <h2>{editingId ? 'Cập nhật sản phẩm' : 'Thêm sản phẩm mới'}</h2>
              <button onClick={handleCloseForm} className="storekeeper-inventory__close-btn">✕</button>
            </div>
            <form onSubmit={handleSubmit} className="storekeeper-inventory__form">
              <div className="storekeeper-inventory__form-group">
                <label>Mã sản phẩm *</label>
                <input
                  type="text"
                  name="item_code"
                  value={formData.item_code}
                  onChange={handleInputChange}
                  placeholder="VD: SK001"
                  disabled={editingId}
                />
              </div>

              <div className="storekeeper-inventory__form-group">
                <label>Tên sản phẩm *</label>
                <input
                  type="text"
                  name="item_name"
                  value={formData.item_name}
                  onChange={handleInputChange}
                  placeholder="VD: Thức ăn tôm"
                />
              </div>

              <div className="storekeeper-inventory__form-row">
                <div className="storekeeper-inventory__form-group">
                  <label>Danh mục *</label>
                  <select name="category_id" value={formData.category_id} onChange={handleInputChange}>
                    <option value="">Chọn danh mục</option>
                    {categories.map((cat) => (
                      <option key={cat.category_id} value={cat.category_id}>
                        {cat.category_name}
                      </option>
                    ))}
                  </select>
                </div>

                <div className="storekeeper-inventory__form-group">
                  <label>Đơn vị *</label>
                  <input
                    type="text"
                    name="unit"
                    value={formData.unit}
                    onChange={handleInputChange}
                    placeholder="VD: kg, lít"
                  />
                </div>
              </div>

              <div className="storekeeper-inventory__form-row">
                <div className="storekeeper-inventory__form-group">
                  <label>Đơn giá</label>
                  <input
                    type="number"
                    name="unit_price"
                    value={formData.unit_price}
                    onChange={handleInputChange}
                    placeholder="0"
                    step="0.01"
                  />
                </div>

                <div className="storekeeper-inventory__form-group">
                  <label>Tối thiểu</label>
                  <input
                    type="number"
                    name="min_quantity"
                    value={formData.min_quantity}
                    onChange={handleInputChange}
                    placeholder="0"
                    step="0.01"
                  />
                </div>

                <div className="storekeeper-inventory__form-group">
                  <label>Tối đa</label>
                  <input
                    type="number"
                    name="max_quantity"
                    value={formData.max_quantity}
                    onChange={handleInputChange}
                    placeholder="0"
                    step="0.01"
                  />
                </div>
              </div>

              <div className="storekeeper-inventory__form-group">
                <label>Nhà cung cấp</label>
                <input
                  type="text"
                  name="supplier"
                  value={formData.supplier}
                  onChange={handleInputChange}
                  placeholder="Tên nhà cung cấp"
                />
              </div>

              <div className="storekeeper-inventory__form-group">
                <label>Mô tả</label>
                <textarea
                  name="description"
                  value={formData.description}
                  onChange={handleInputChange}
                  placeholder="Mô tả sản phẩm"
                  rows="3"
                ></textarea>
              </div>

              <div className="storekeeper-inventory__form-group">
                <label>Trạng thái</label>
                <select name="status" value={formData.status} onChange={handleInputChange}>
                  <option value="ACTIVE">Hoạt động</option>
                  <option value="INACTIVE">Không hoạt động</option>
                </select>
              </div>

              <div className="storekeeper-inventory__modal-actions">
                <button type="submit" className="storekeeper-inventory__button-primary">
                  {editingId ? '💾 Cập nhật' : '➕ Tạo mới'}
                </button>
                <button type="button" onClick={handleCloseForm} className="storekeeper-inventory__button-secondary">
                  ✕ Hủy
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {loading ? (
        <div className="storekeeper-inventory__loading">Đang tải...</div>
      ) : (
        <div className="storekeeper-inventory__table-wrapper">
          <table className="storekeeper-inventory__table">
            <thead>
              <tr>
                <th>Mã sản phẩm</th>
                <th>Tên sản phẩm</th>
                <th>Danh mục</th>
                <th>Đơn vị</th>
                <th>Đơn giá</th>
                <th>Tối thiểu</th>
                <th>Tối đa</th>
                <th>Trạng thái</th>
                <th>Hành động</th>
              </tr>
            </thead>
            <tbody>
              {filteredItems.length > 0 ? (
                filteredItems.map((item) => (
                  <tr key={item.item_id}>
                    <td className="storekeeper-inventory__code">{item.item_code}</td>
                    <td>{item.item_name}</td>
                    <td>{item.category_name}</td>
                    <td>{item.unit}</td>
                    <td>{parseFloat(item.unit_price || 0).toLocaleString('vi-VN')} VNĐ</td>
                    <td>{parseFloat(item.min_quantity || 0).toFixed(2)}</td>
                    <td>{parseFloat(item.max_quantity || 0).toFixed(2)}</td>
                    <td>
                      <span className={`storekeeper-inventory__status storekeeper-inventory__status--${item.status.toLowerCase()}`}>
                        {item.status === 'ACTIVE' ? '✓ Hoạt động' : '✕ Không hoạt động'}
                      </span>
                    </td>
                    <td className="storekeeper-inventory__actions">
                      <button onClick={() => handleEdit(item)} className="storekeeper-inventory__button-edit" title="Sửa">
                        ✏️
                      </button>
                      <button onClick={() => handleDelete(item.item_id)} className="storekeeper-inventory__button-delete" title="Xóa">
                        🗑️
                      </button>
                    </td>
                  </tr>
                ))
              ) : (
                <tr>
                  <td colSpan="9" className="storekeeper-inventory__empty">
                    Không tìm thấy sản phẩm nào
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
};

export default StorekeeperInventory;
